// Calcula el movimiento del DÍA. Si no hay nada, devuelve [] y el flujo corta acá.
const leads = $('Leer Leads').all().map(i => i.json);
const crm = $('Leer CRM').all().map(i => i.json);
const agenda = $('Leer Agenda').all().map(i => i.json);
const hoyStr = new Date().toISOString().slice(0,10);
const esHoy = (f) => (f || '').toString().slice(0,10) === hoyStr;

const leadsHoy = leads.filter(l => esHoy(l.fecha));
const altasHoy = crm.filter(c => esHoy(c.fecha_alta));
const pagosHoy = crm.filter(c => esHoy(c.fecha_pago) && Number(c.monto_pagado) > 0);
const llamadasHoy = agenda.filter(a => esHoy(a.fecha_hora || a.fecha));

// Saldos pendientes (control de lo que falta cobrar) — para recordarte
const saldos = crm.filter(c => Number(c.saldo_pendiente) > 0)
  .map(c => ({ nombre: c.nombre, saldo: c.saldo_pendiente, estado: c.estado_proyecto }));

const huboMovimiento = leadsHoy.length + altasHoy.length + pagosHoy.length + llamadasHoy.length > 0;
if (!huboMovimiento) { return []; } // ← corta acá, no manda nada, no gasta IA

return [{ json: {
  fecha: hoyStr,
  leads_hoy: leadsHoy.length,
  leads_detalle: leadsHoy.map(l => ({ nombre: l.nombre, canal: l.canal, interes: l.interes, prioridad: l.prioridad })),
  altas_hoy: altasHoy.length,
  altas_detalle: altasHoy.map(c => ({ nombre: c.nombre, servicios: c.servicios, total: c.presupuesto_total, estado: c.estado_proyecto })),
  pagos_hoy: pagosHoy.map(c => ({ nombre: c.nombre, monto: c.monto_pagado, estado: c.pago_estado })),
  llamadas_hoy: llamadasHoy.map(a => ({ nombre: a.nombre, hora: a.fecha_hora, tema: a.tema })),
  saldos_pendientes: saldos
}}];
